        payload: { pluginId: 'codegraphy.python', enabled: false },
      },
      state,
      handlers,
    );

    expect(handled).toBe(true);
    expect(handlers.smartRebuild).toHaveBeenCalledWith('codegraphy.python');
    expect(handlers.reprocessPluginFiles).not.toHaveBeenCalled();
  });
});

